我来实现一个线程安全的单例模式，使用 C++17 的 `std::call_once` 和 Meyer's Singleton 两种方式，并详细说明原理。

## 完整实现

```cpp
#include <iostream>
#include <mutex>
#include <memory>
#include <string>
#include <thread>
#include <vector>
#include <chrono>

// ============================================================
// 方式一：使用 std::call_once（显式控制初始化）
// ============================================================

template <typename T>
class SingletonCallOnce {
public:
    // 获取单例实例
    template <typename... Args>
    static T& getInstance(Args&&... args) {
        // std::call_once 保证函数只执行一次，线程安全
        std::call_once(initFlag_, &SingletonCallOnce::init<Args...>, 
                      std::forward<Args>(args)...);
        return *instance_;
    }

    // 禁用拷贝和移动
    SingletonCallOnce(const SingletonCallOnce&) = delete;
    SingletonCallOnce& operator=(const SingletonCallOnce&) = delete;
    SingletonCallOnce(SingletonCallOnce&&) = delete;
    SingletonCallOnce& operator=(SingletonCallOnce&&) = delete;

private:
    // 私有构造函数
    SingletonCallOnce() = default;

    template <typename... Args>
    static void init(Args&&... args) {
        // 使用 unique_ptr 管理生命周期，异常安全
        instance_.reset(new T(std::forward<Args>(args)...));

        // 注册销毁函数（可选）
        std::atexit(destroy);
    }

    static void destroy() {
        instance_.reset();
    }

    static std::once_flag initFlag_;      // 初始化标志
    static std::unique_ptr<T> instance_;  // 实例指针
};

// 静态成员定义
template <typename T>
std::once_flag SingletonCallOnce<T>::initFlag_;

template <typename T>
std::unique_ptr<T> SingletonCallOnce<T>::instance_;


// ============================================================
// 方式二：Meyer's Singleton（C++11起线程安全）
// ============================================================

template <typename T>
class SingletonMeyer {
public:
    // 获取单例实例 - 局部静态变量方式
    template <typename... Args>
    static T& getInstance(Args&&... args) {
        // C++11 起，局部静态变量初始化是线程安全的
        // 编译器会自动插入同步机制（通常是原子操作 + 锁）
        static T instance(std::forward<Args>(args)...);
        return instance;
    }

    // 禁用拷贝和移动
    SingletonMeyer(const SingletonMeyer&) = delete;
    SingletonMeyer& operator=(const SingletonMeyer&) = delete;

private:
    SingletonMeyer() = default;
};


// ============================================================
// 测试用的实际类
// ============================================================

class Database {
public:
    Database() {
        std::cout << "Database 默认构造" << std::endl;
    }

    explicit Database(std::string host, int port) 
        : host_(std::move(host)), port_(port) {
        std::cout << "Database 构造: " << host_ << ":" << port_ 
                  << " @ " << std::this_thread::get_id() << std::endl;

        // 模拟耗时初始化
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }

    void query(const std::string& sql) {
        std::lock_guard<std::mutex> lock(mutex_);
        std::cout << "[" << host_ << ":" << port_ << "] 执行: " << sql 
                  << " @ thread " << std::this_thread::get_id() << std::endl;
    }

private:
    std::string host_ = "localhost";
    int port_ = 3306;
    std::mutex mutex_;
};

class Logger {
public:
    Logger() {
        std::cout << "Logger 构造 @ " << std::this_thread::get_id() << std::endl;
    }

    void log(const std::string& msg) {
        std::lock_guard<std::mutex> lock(mutex_);
        std::cout << "[LOG] " << msg << std::endl;
    }

private:
    std::mutex mutex_;
};


